export const VOCAB_BASE64 = "";

export function decodeVocab(): VocabItem[] {
  try {
    const binary = atob(VOCAB_BASE64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    const json = new TextDecoder('utf-8').decode(bytes);
    return JSON.parse(json);
  } catch {
    return [];
  }
}

export interface VocabItem {
  word: string;
  phonetic: string;
  meaning_cn: string;
  meaning_en: string;
  example_en: string;
  example_cn: string;
}
